sql:
SELECT feature_type, AVG(feature_quality_score) AS avg_feature_quality_score
FROM gait_features
GROUP BY feature_type;

SELECT feature_name 
FROM gait_features 
WHERE feature_quality_score > 0.9 AND feature_source = 'sensor';

SELECT important_feature_importances
FROM gait_data
WHERE gait_id = 0;

SELECT model_used, COUNT(*) as total_entries
FROM gait_data
GROUP BY model_used;

SELECT AVG(important_feature_importances) AS average_feature_importance
FROM gait_data
WHERE data_source = 'sensor';

SELECT * 
FROM gait_data 
WHERE session_id = 123;

